static void copy_path (char* dst, u16 n, cstr src) {
    if (!src) {
        src = "";
    }
    std::snprintf(dst, n, "%s", src);
}

static void join_path (char* dst, u16 n, cstr base, cstr suffix) {
    if (!base) {
        base = "";
    }
    if (!suffix) {
        suffix = "";
    }
    const u32 bl = (u32)std::strlen(base);
    const u32 sl = (u32)std::strlen(suffix);
    if (n == 0 || bl + 1u + sl >= n) {
        if (n > 0) {
            dst[0] = '\0';
        }
        return;
    }
    std::memcpy(dst, base, bl);
    dst[bl] = '/';
    std::memcpy(dst + bl + 1, suffix, sl + 1);
}

static bool does_file_exist (cstr path) {
    if (!path || !path[0]) {
        return false;
    }
    FILE* f = std::fopen(path, "r");
    if (!f) {
        return false;
    }
    std::fclose(f);
    return true;
}

